export async function seedVenues() {
  try {
    let inserted = 0;
    let skipped = 0;

    for (const venue of VENUES) {
      const result = await db.execute(sql`
        INSERT INTO spotlighted_places (name, lat, lon, category, address, website, admin_note, active, admin_id)
        SELECT
          ${venue.name},
          ${venue.lat},
          ${venue.lon},
          ${venue.category},
          ${venue.address},
          ${venue.website ?? null},
          ${venue.adminNote ?? null},
          ${venue.active},
          3
        WHERE NOT EXISTS (
          SELECT 1 FROM spotlighted_places WHERE name = ${venue.name}
        )
      `);
      if ((result as any).rowCount > 0) {
        inserted++;
      } else {
        skipped++;
      }
    }

    console.log(`✅ Venue seed complete: ${inserted} inserted, ${skipped} already existed`);
  } catch (error) {
    console.error("❌ Venue seed failed:", error);
  }
}

// Correct known bad venue data in any environment (runs at every startup, safe to re-run)
export async function correctVenueData() {
  try {
    const corrections = [
      sql`UPDATE spotlighted_places SET website = 'https://www.cafebrinkmann.nl' WHERE name = 'Café Brinkmann Haarlem' AND (website IS NULL OR website = 'https://bruegge.nl')`,
      sql`UPDATE spotlighted_places SET website = 'https://www.cafeledigeerf.nl' WHERE name = 'Café Ledig Erf Utrecht' AND (website IS NULL OR website LIKE '%cafuul%')`,
      sql`UPDATE spotlighted_places SET website = 'https://www.depaviljoen.nl' WHERE name = 'De Paviljoens Almere' AND (website IS NULL OR website LIKE '%paviljoenss%')`,
      sql`UPDATE spotlighted_places SET website = 'https://noboamsterdam.nl', admin_note = 'Stylish neighbourhood café-restaurant in Amsterdam Oost. Good coffee, plant-based food, urban art on the walls.' WHERE name = 'Nōbo' AND (website IS NULL OR website = '')`,
      sql`UPDATE spotlighted_places SET website = 'https://boerderijmeerzicht.nl', admin_note = 'Iconic farmhouse café in Amsterdamse Bos on the water — terrace, pancakes, and a beloved community gathering spot.' WHERE name = 'Boerderij Meerzicht' AND (website IS NULL OR website = '')`,
      sql`UPDATE spotlighted_places SET name = 'VOLT Haarlem', website = 'https://volt-haarlem.nl', admin_note = 'Underground hip-hop and urban music nights in central Haarlem. Local talent, rap battles and DJ sets.' WHERE name = 'Poppodium Haarlem'`,
      sql`UPDATE spotlighted_places SET active = true WHERE name = 'Shelter Amsterdam' AND active = false`,
    ];
    for (const stmt of corrections) {
      await db.execute(stmt);
    }
    console.log(`✅ Venue corrections applied`);
  } catch (error) {
    console.error("❌ Venue corrections failed:", error);
  }
}
